import{_ as t,c as e,o as r,ag as o}from"./chunks/framework.bCALENAD.js";const l="/assets/TypeAnnotations.zj-Euo-U.png",g=JSON.parse('{"title":"TypeScript","description":"","frontmatter":{},"headers":[],"relativePath":"notes/ts/index.md","filePath":"notes/ts/index.md","lastUpdated":1772184979000}'),n={name:"notes/ts/index.md"};function i(s,a,h,d,c,u){return r(),e("div",null,[...a[0]||(a[0]=[o('<h1 id="typescript" tabindex="-1">TypeScript <a class="header-anchor" href="#typescript" aria-label="Permalink to &quot;TypeScript&quot;">​</a></h1><h2 id="综述" tabindex="-1">综述 <a class="header-anchor" href="#综述" aria-label="Permalink to &quot;综述&quot;">​</a></h2><h3 id="是什么" tabindex="-1">是什么 <a class="header-anchor" href="#是什么" aria-label="Permalink to &quot;是什么&quot;">​</a></h3><ul><li>TypeScript（简称：TS）是 JavaScript 的超集（JS 有的 TS 都有）。</li><li>TypeScript = Type + JavaScript（在 JS 基础之上，为 JS 添加了类型支持）。</li><li>TypeScript 是微软开发的开源编程语言，可以在任何运行 JavaScript 的地方运行。</li></ul><h3 id="为什么" tabindex="-1">为什么 <a class="header-anchor" href="#为什么" aria-label="Permalink to &quot;为什么&quot;">​</a></h3><ul><li>背景：JS 的类型系统存在“先天缺陷”，JS 代码中绝大部分错误都是<strong>类型错误</strong>（Uncaught TypeError）。</li><li>问题：增加了找 Bug、改 Bug 的时间，严重影响开发效率。</li></ul><p>从编程语言的动静态来区分，TypeScript 属于<strong>静态类型的编程语言</strong>，JS 属于<strong>动态类型的编程语言</strong>。</p><ul><li><strong>静态类型：</strong> 编译期做类型检查</li><li><strong>动态类型：</strong> 执行期做类型检查</li></ul><p><strong>代码编译和代码执行的顺序：1 编译 → 2 执行</strong></p><ul><li>对于 JS 来说：需要等到代码真正去<strong>执行</strong>的时候才能<strong>发现错误</strong>（晚）。</li><li>对于 TS 来说：在代码<strong>编译</strong>的时候（代码执行前）就可以<strong>发现错误</strong>（早）。</li><li>配合 VSCode 等开发工具，TS 可以<strong>提前到在编写代码的同时</strong>就发现代码中的错误，减少找 Bug、改 Bug 时间。</li></ul><h3 id="优势" tabindex="-1">优势 <a class="header-anchor" href="#优势" aria-label="Permalink to &quot;优势&quot;">​</a></h3><ol><li>更早（写代码的同时）发现错误，减少找 Bug、改 Bug 时间，提升开发效率。</li><li>程序中任何位置的代码都有<strong>代码提示</strong>，随时随地的安全感，增强了开发体验。</li><li>强大的<strong>类型系统</strong>提升了代码的可维护性，使得<strong>重构代码更加容易</strong>。</li><li>支持最新的 <strong>ECMAScript 语法</strong>，优先体验最新的语法，让你走在前端技术的最前沿。</li><li>TS 类型推断机制，<strong>不需要在代码中的每个地方都显式标注类型</strong>，让你在享受优势的同时，尽量降低了成本。</li></ol><blockquote><p>除此之外，Vue 3 源码使用 TS 重写、Angular 默认支持 TS、React 与 TS 完美配合，TypeScript 已成为大中型前端项目的首选编程语言。</p></blockquote><h2 id="初体验" tabindex="-1">初体验 <a class="header-anchor" href="#初体验" aria-label="Permalink to &quot;初体验&quot;">​</a></h2><h3 id="安装编译ts的工具包" tabindex="-1">安装编译TS的工具包 <a class="header-anchor" href="#安装编译ts的工具包" aria-label="Permalink to &quot;安装编译TS的工具包&quot;">​</a></h3><p><strong>问题：为什么要安装编译 TS 的工具包？</strong></p><p><strong>回答：</strong> Node.js / 浏览器，只认识 JS 代码，不认识 TS 代码。需要先将 TS 代码转化为 JS 代码，然后才能运行。</p><p><strong>安装命令：</strong> <code>npm i -g typescript</code></p><p><strong>typescript 包：</strong> 用来编译 TS 代码的包，提供了 <code>tsc</code> 命令，实现了 TS → JS 的转化。</p><p><strong>验证是否安装成功：</strong> <code>tsc -v</code>（查看 typescript 的版本）</p><h3 id="编译并运行ts代码" tabindex="-1">编译并运行TS代码 <a class="header-anchor" href="#编译并运行ts代码" aria-label="Permalink to &quot;编译并运行TS代码&quot;">​</a></h3><ol><li>创建 <code>hello.ts</code> 文件（注意：TS 文件的后缀名为 <code>.ts</code>）。</li><li>将 TS 编译为 JS：在终端中输入命令，<code>tsc hello.ts</code>（此时，在同级目录中会出现一个同名的 JS 文件）。</li><li>执行 JS 代码：在终端中输入命令，<code>node hello.js</code>。</li></ol><ul><li><strong>1 创建 ts 文件</strong> → <strong>2 编译 TS</strong> → <strong>3 执行 JS</strong></li></ul><blockquote><p><strong>说明：</strong> 所有合法的 JS 代码都是 TS 代码，有 JS 基础只需要学习 TS 的类型即可。</p><p><strong>注意：</strong> 由 TS 编译生成的 JS 文件，代码中就没有类型信息了。</p></blockquote><h3 id="简化运行ts的步骤" tabindex="-1">简化运行TS的步骤 <a class="header-anchor" href="#简化运行ts的步骤" aria-label="Permalink to &quot;简化运行TS的步骤&quot;">​</a></h3><p><strong>问题描述：</strong> 每次修改代码后，都要重复执行两个命令，才能运行 TS 代码，太繁琐。</p><p><strong>简化方式：</strong> 使用 <code>ts-node</code> 包，直接在 Node.js 中执行 TS 代码。</p><p><strong>安装命令：</strong> <code>npm i -g ts-node</code></p><p><strong>使用方式：</strong> <code>ts-node hello.ts</code></p><p><strong>解释：</strong> <code>ts-node</code> 命令在内部偷偷地将 TS → JS，然后，再运行 JS 代码。</p><h2 id="常用基础类型" tabindex="-1">常用基础类型 <a class="header-anchor" href="#常用基础类型" aria-label="Permalink to &quot;常用基础类型&quot;">​</a></h2><p>TypeScript 是 JS 的超集，TS 提供了 JS 的所有功能，并且额外增加了：<strong>类型系统</strong>。</p><ul><li>所有的 JS 代码都是 TS 代码。</li><li>JS 有类型（比如，number/string 等），但是 <strong>JS 不会检查变量的类型是否发生变化</strong>。而 <strong>TS 会检查</strong>。</li></ul><p>TypeScript 类型系统的主要优势：可以<strong>显示标记出代码中的意外行为</strong>，从而降低了发生错误的可能性。</p><hr><p><strong>类型注解</strong></p><p><img src="'+l+'" alt="类型注解"></p><h3 id="原始类型" tabindex="-1">原始类型 <a class="header-anchor" href="#原始类型" aria-label="Permalink to &quot;原始类型&quot;">​</a></h3><h3 id="数组类型-含联合类型说明" tabindex="-1">数组类型（含联合类型说明） <a class="header-anchor" href="#数组类型-含联合类型说明" aria-label="Permalink to &quot;数组类型（含联合类型说明）&quot;">​</a></h3><h3 id="类型别名" tabindex="-1">类型别名 <a class="header-anchor" href="#类型别名" aria-label="Permalink to &quot;类型别名&quot;">​</a></h3><h3 id="函数类型" tabindex="-1">函数类型 <a class="header-anchor" href="#函数类型" aria-label="Permalink to &quot;函数类型&quot;">​</a></h3><h3 id="对象类型" tabindex="-1">对象类型 <a class="header-anchor" href="#对象类型" aria-label="Permalink to &quot;对象类型&quot;">​</a></h3><h3 id="接口" tabindex="-1">接口 <a class="header-anchor" href="#接口" aria-label="Permalink to &quot;接口&quot;">​</a></h3><h3 id="元组" tabindex="-1">元组 <a class="header-anchor" href="#元组" aria-label="Permalink to &quot;元组&quot;">​</a></h3><h3 id="类型推论" tabindex="-1">类型推论 <a class="header-anchor" href="#类型推论" aria-label="Permalink to &quot;类型推论&quot;">​</a></h3><h3 id="类型断言" tabindex="-1">类型断言 <a class="header-anchor" href="#类型断言" aria-label="Permalink to &quot;类型断言&quot;">​</a></h3><h3 id="字面量类型" tabindex="-1">字面量类型 <a class="header-anchor" href="#字面量类型" aria-label="Permalink to &quot;字面量类型&quot;">​</a></h3><h3 id="枚举" tabindex="-1">枚举 <a class="header-anchor" href="#枚举" aria-label="Permalink to &quot;枚举&quot;">​</a></h3><h3 id="any-类型" tabindex="-1"><code>any</code> 类型 <a class="header-anchor" href="#any-类型" aria-label="Permalink to &quot;`any` 类型&quot;">​</a></h3><h2 id="高级类型" tabindex="-1">高级类型 <a class="header-anchor" href="#高级类型" aria-label="Permalink to &quot;高级类型&quot;">​</a></h2><h3 id="class-类" tabindex="-1">class 类 <a class="header-anchor" href="#class-类" aria-label="Permalink to &quot;class 类&quot;">​</a></h3><h3 id="类型兼容性" tabindex="-1">类型兼容性 <a class="header-anchor" href="#类型兼容性" aria-label="Permalink to &quot;类型兼容性&quot;">​</a></h3><h3 id="交叉类型" tabindex="-1">交叉类型 <a class="header-anchor" href="#交叉类型" aria-label="Permalink to &quot;交叉类型&quot;">​</a></h3><h3 id="泛型" tabindex="-1">泛型 <a class="header-anchor" href="#泛型" aria-label="Permalink to &quot;泛型&quot;">​</a></h3><h3 id="索引签名类型" tabindex="-1">索引签名类型 <a class="header-anchor" href="#索引签名类型" aria-label="Permalink to &quot;索引签名类型&quot;">​</a></h3><h3 id="映射类型" tabindex="-1">映射类型 <a class="header-anchor" href="#映射类型" aria-label="Permalink to &quot;映射类型&quot;">​</a></h3><h2 id="类型声明文件" tabindex="-1">类型声明文件 <a class="header-anchor" href="#类型声明文件" aria-label="Permalink to &quot;类型声明文件&quot;">​</a></h2><h3 id="两种文件类型" tabindex="-1">两种文件类型 <a class="header-anchor" href="#两种文件类型" aria-label="Permalink to &quot;两种文件类型&quot;">​</a></h3><h3 id="类型声明文件的使用说明" tabindex="-1">类型声明文件的使用说明 <a class="header-anchor" href="#类型声明文件的使用说明" aria-label="Permalink to &quot;类型声明文件的使用说明&quot;">​</a></h3>',59)])])}const S=t(n,[["render",i]]);export{g as __pageData,S as default};
